import React, { useEffect, useState } from "react";
import { supabase } from "../supabaseClient";
import { 
    Navigation, LogOut, Search, RefreshCcw, 
    MessageCircle, MapPin, Clock, Calendar, 
    CheckCircle, XCircle, Send, Phone, User, Loader2
} from "lucide-react";
import "./Dashboard.css";

const Dashboard = ({ session }) => {
    const [rides, setRides] = useState([]);
    const [search, setSearch] = useState("");
    const [filter, setFilter] = useState("all");
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        fetchRides();
        const sub = supabase.channel('global-rides').on('postgres_changes', { event: '*', schema: 'public', table: 'rides' }, () => fetchRides()).subscribe();
        return () => supabase.removeChannel(sub);
    }, []);

    const fetchRides = async () => {
        const { data } = await supabase.from("rides").select("*").order("created_at", { ascending: false });
        if (data) setRides(data);
        setLoading(false);
    };

    const updateStatus = async (id, status) => {
        await supabase.from('rides').update({ status }).eq('id', id);
        fetchRides();
    };

    const triggerWhatsApp = (num, name, type) => {
        const cleanNum = num.replace(/\D/g, '');
        const msg = type === 'alt' 
            ? `Hello, reaching out regarding ${name}'s PAHEL ride booking.` 
            : `Hi ${name}, your PAHEL ride booking has been received and is being processed.`;
        window.open(`https://wa.me/91${cleanNum}?text=${encodeURIComponent(msg)}`, '_blank');
    };

    const stats = {
        total: rides.length,
        pending: rides.filter(r => r.status === 'pending').length,
        today: rides.filter(r => r.ride_date === new Date().toISOString().split('T')[0]).length,
        completed: rides.filter(r => r.status === 'completed').length
    };

    const filtered = rides.filter(r => {
        const matchSearch = r.passenger_name.toLowerCase().includes(search.toLowerCase()) || r.phone_number.includes(search);
        const matchFilter = filter === 'all' || r.status === filter;
        return matchSearch && matchFilter;
    });

    if (loading) return <div style={{display:'flex', height:'100vh', justifyContent:'center', alignItems:'center'}}><Loader2 className="animate-spin" color="#2563eb" /></div>;

    return (
        <div className="dashboard-container">
            {/* Header */}
            <header className="top-bar">
                <div className="brand-title">
                    <div style={{background: 'var(--primary)', padding: '8px', borderRadius: '10px'}}>
                        <Navigation color="#fff" size={24} fill="#fff" />
                    </div>
                    PAHEL OPS COMMAND
                </div>
                <div style={{display:'flex', alignItems:'center', gap: '20px'}}>
                    <span style={{color: 'var(--text-muted)', fontWeight: 500}}>{session.user.email}</span>
                    <button className="logout-btn" onClick={() => supabase.auth.signOut()}>
                        <LogOut size={18} /> Sign Out
                    </button>
                </div>
            </header>

            {/* Stats Row */}
            <div className="stats-row">
                <div className="stat-card">
                    <span className="stat-label">Total Volume</span>
                    <span className="stat-number" style={{color: 'var(--text-main)'}}>{stats.total}</span>
                </div>
                <div className="stat-card">
                    <span className="stat-label">Awaiting Action</span>
                    <span className="stat-number" style={{color: 'var(--warning)'}}>{stats.pending}</span>
                </div>
                <div className="stat-card">
                    <span className="stat-label">Scheduled Today</span>
                    <span className="stat-number" style={{color: 'var(--primary)'}}>{stats.today}</span>
                </div>
                <div className="stat-card">
                    <span className="stat-label">Completed Trips</span>
                    <span className="stat-number" style={{color: 'var(--success)'}}>{stats.completed}</span>
                </div>
            </div>

            {/* Main Data Card */}
            <div className="data-card">
                <div className="table-controls">
                    <div style={{display:'flex', gap:'15px'}}>
                        <input 
                            type="text" 
                            className="search-box" 
                            placeholder="Search by name or mobile..." 
                            onChange={(e) => setSearch(e.target.value)}
                        />
                        <select className="search-box" style={{width: '180px'}} onChange={(e) => setFilter(e.target.value)}>
                            <option value="all">All Status</option>
                            <option value="pending">Pending</option>
                            <option value="confirmed">Confirmed</option>
                            <option value="completed">Completed</option>
                        </select>
                    </div>
                    <button className="logout-btn" style={{color: 'var(--primary)'}} onClick={fetchRides}>
                        <RefreshCcw size={18} /> Refresh
                    </button>
                </div>

                <table className="main-table">
                    <thead>
                        <tr>
                            <th>Passenger Details</th>
                            <th>Contact Channels</th>
                            <th>Route Information</th>
                            <th>Date & Time</th>
                            <th>Status</th>
                            <th style={{textAlign: 'right'}}>Actions</th>
                        </tr>
                    </thead>
                    <tbody>
                        {filtered.map(ride => (
                            <tr key={ride.id}>
                                <td>
                                    <div style={{fontWeight: 700, fontSize: '15px', color: 'var(--text-main)'}}>{ride.passenger_name}</div>
                                    <div style={{fontSize: '12px', color: 'var(--text-muted)', marginTop: '2px'}}>ID: #{ride.id.slice(0,8)}</div>
                                </td>
                                <td>
                                    <button onClick={() => triggerWhatsApp(ride.phone_number, ride.passenger_name, 'main')} className="contact-pill">
                                        <MessageCircle size={14} /> Main: {ride.phone_number}
                                    </button>
                                    {ride.alt_phone && (
                                        <button onClick={() => triggerWhatsApp(ride.alt_phone, ride.passenger_name, 'alt')} className="contact-pill alt-pill">
                                            <MessageCircle size={14} /> Alt: {ride.alt_phone}
                                        </button>
                                    )}
                                </td>
                                <td>
                                    <div style={{display:'flex', alignItems:'center', gap:'6px', color: 'var(--success)', fontWeight: 600, fontSize: '13px'}}>
                                        <MapPin size={12}/> {ride.pickup_location}
                                    </div>
                                    <div style={{display:'flex', alignItems:'center', gap:'6px', color: 'var(--danger)', fontSize: '13px', marginTop: '6px'}}>
                                        <MapPin size={12}/> {ride.drop_location}
                                    </div>
                                </td>
                                <td>
                                    <div style={{fontWeight: 600}}><Calendar size={12} style={{marginRight: '4px'}}/>{ride.ride_date}</div>
                                    <div style={{color: 'var(--text-muted)', fontSize: '13px'}}><Clock size={12} style={{marginRight: '4px'}}/>{ride.ride_time}</div>
                                </td>
                                <td>
                                    <span className={`status-tag ${ride.status}`}>{ride.status}</span>
                                </td>
                                <td>
                                    <div style={{display:'flex', gap: '8px', justifyContent: 'flex-end'}}>
                                        <button onClick={() => updateStatus(ride.id, 'confirmed')} title="Confirm" className="logout-btn" style={{padding:'8px', color: 'var(--primary)'}}><Send size={16}/></button>
                                        <button onClick={() => updateStatus(ride.id, 'completed')} title="Complete" className="logout-btn" style={{padding:'8px', color: 'var(--success)'}}><CheckCircle size={16}/></button>
                                        <button onClick={() => updateStatus(ride.id, 'cancelled')} title="Cancel" className="logout-btn" style={{padding:'8px', color: 'var(--danger)'}}><XCircle size={16}/></button>
                                    </div>
                                </td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            </div>
        </div>
    );
};

export default Dashboard;
